/// Squaring each element of a vector in place.
/// The implementation uses OpenMP parallelism and
/// gcc's vectorisation hints for maximum throughput.
inline void squareEach(std::vector<int> &x) noexcept {
    const size_t n = x.size();
    if (n == 0) return;

    // Avoid dynamic allocation and virtual dispatch.
    // Access the underlying storage directly.
    int *ptr = x.data();

#pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < n; ++i) {
        // The compiler will auto‑vectorise this loop under -O2.
        int v = ptr[i];
        ptr[i] = v * v;
    }
}
