#pragma once
#include <vector>

/*
 * Return the product of the vector x with every odd indexed element inverted.
 * i.e. x_0 * 1/x_1 * x_2 * 1/x_3 * x_4 ...
 * Example:
 *   input: [4, 2, 10, 4, 5]
 *   output: 25
 *
 * This implementation avoids allocating an intermediate vector and
 * performs a parallel reduction using OpenMP, which gives a speedup
 * on multi‑core machines while preserving exact arithmetic behaviour.
 */
double productWithInverses(const std::vector<double>& x)
{
    if (x.empty()) return 1.0;                     // product of empty set

    double product = 1.0;
#pragma omp parallel for reduction(*:product)
    for (std::size_t i = 0; i < x.size(); ++i)
    {
        const double val = (i & 1) ? (1.0 / x[i]) : x[i];
        product *= val;
    }

    return product;
}
