void firstLetterCounts(const std::vector<std::string> &s, std::array<size_t, 26> &bins) {
    const int n_threads = omp_get_max_threads();
    // Each thread keeps a private bin array
    std::vector<std::array<size_t, 26>> local_bins(n_threads);
    for (int t = 0; t < n_threads; ++t) local_bins[t].fill(0);

    #pragma omp parallel
    {
        const int tid = omp_get_thread_num();
        const int chunk = (s.size() + n_threads - 1) / n_threads;
        const size_t start = tid * chunk;
        const size_t end   = std::min(start + chunk, static_cast<size_t>(s.size()));

        auto &lb = local_bins[tid];
        for (size_t i = start; i < end; ++i) {
            const char c = s[i][0];
            const int idx = c - 'a';
            lb[idx] += 1;
        }
    }

    // Reduce local bins into the result
    bins.fill(0);
    for (const auto &lb : local_bins) {
        for (int i = 0; i < 26; ++i) {
            bins[i] += lb[i];
        }
    }
}
