34_scan_largest_contiguous_subarray_sum:
```cpp
#pragma once
#include <vector>
#include <limits>
#include <algorithm>
#include <numeric>

/* Optimal linear‑time implementation of the maximum sub‑array problem
   (Kadane's algorithm).  It preserves the exact semantics of the
   original quadratic routine, including the handling of all‑negative
   input vectors.  The algorithm runs in O(n) time and is embarrassingly
   serial, but the constant factors are reduced by avoiding bounds
   checks and by using compiler optimisations. */

int maximumSubarray(std::vector<int> const& x) {
    if (x.empty())
        return std::numeric_limits<int>::lowest();   // defined behaviour

    int max_ending_here = x[0];
    int max_so_far = x[0];

    // Use raw pointer iteration to reduce overhead
    const int* it = &x[0];
    const int* end = it + x.size();

    for (; it != end; ++it) {
        // The first element is already handled; skip it
        if (it == &x[0]) continue;

        // Update max_ending_here in the most compact form
        max_ending_here = std::max(*it, max_ending_here + *it);
        // Update global maximum
        max_so_far = std::max(max_so_far, max_ending_here);
    }

    return max_so_far;
}
