#pragma once
#include <vector>
#include <array>
#include <cstddef>
#include <cstring>
#include <omp.h>

/* Count the number of pixels in image with each grayscale intensity.
   The vector `image` is a grayscale image with values 0-255.
   Store the results in `bins`.
   Example:

   input: image=[2, 116, 201, 11, 92, 92, 201, 4, 2]
   output: [0, 0, 2, 0, 1, ...]
*/
void pixelCounts(std::vector<int> const& image, std::array<size_t, 256> &bins) {
    // Zero the result array
    std::fill(bins.begin(), bins.end(), 0);

    // Number of threads (use default OpenMP schedule)
    int nthreads = 1;
    #pragma omp parallel
    {
        #pragma omp single
        nthreads = omp_get_num_threads();
    }

    // Thread‑local histogram
    std::vector<std::array<size_t, 256>> local(nthreads);
    for (auto &a : local) std::fill(a.begin(), a.end(), 0);

    // Parallel histogram construction
    #pragma omp parallel for schedule(static)
    for (size_t idx = 0; idx < image.size(); ++idx) {
        int pixel = image[idx];
        int tid   = omp_get_thread_num();
        local[tid][pixel] += 1;
    }

    // Merge local histograms into the global result
    for (int t = 0; t < nthreads; ++t) {
        for (int v = 0; v < 256; ++v) {
            bins[v] += local[t][v];
        }
    }
}
