19_graph_shortest_path:
```cpp
#pragma once
#include <vector>
#include <limits>

/* Return the length of the shortest path from source to dest in the undirected graph
   defined by the adjacency matrix A.  A is an NxN adjacency matrix stored in
   row-major order.  The graph is connected and undirected. */
int shortestPathLength(std::vector<int> const& A, size_t N, int source, int dest) noexcept {
    // Distance array: -1  ->  unvisited
    std::vector<int> dist(N, -1);
    // Simple circular queue (array) – enough for all vertices
    std::vector<int> q(N);
    size_t head = 0, tail = 0;

    // Start BFS
    dist[source] = 0;
    q[tail++] = source;

    const int *adj = A.data();          // pointers for faster access

    while (head < tail) {
        int cur = q[head++];
        int curDist = dist[cur];
        if (cur == dest) return curDist;

        // Scan row cur for adjacent vertices
        const int *row = adj + cur * N;
        for (size_t i = 0; i < N; ++i) {
            if (row[i] && dist[i] == -1) {
                dist[i] = curDist + 1;
                q[tail++] = static_cast<int>(i);
            }
        }
    }
    // Graph is connected, but keep the original semantics
    return std::numeric_limits<int>::max();
}
