#pragma once
#include <array>
#include <vector>
#include <cstddef>
#include <cstdint>
#include <omp.h>

struct Point {
    double x, y;
};

/*
 * Counts the number of points that lie in each quadrant.
 *     bins[0] – Q1 (x ≥ 0, y ≥ 0)
 *     bins[1] – Q2 (x <  0, y ≥ 0)
 *     bins[2] – Q3 (x <  0, y <  0)
 *     bins[3] – Q4 (x ≥ 0, y <  0)
 *
 * The function is fully parallelised with OpenMP and respects the original
 * semantics (order of processing does not matter for a pure counting job).
 */
inline void countQuadrants(std::vector<Point> const& points, std::array<std::size_t, 4> &bins) {
    // Initialise local bin counters for each thread to avoid atomic ops
    const std::size_t nthreads = omp_get_max_threads();
    std::vector<std::array<std::size_t, 4>> localBins(nthreads);
    for (auto &b : localBins) b.fill(0);

    #pragma omp parallel
    {
        const std::size_t idx = omp_get_thread_num();
        std::array<std::size_t, 4> *b = &localBins[idx];

        // Use a pointer to the data for a small cache‑friendly loop
        const Point* ptr = points.data();
        const std::size_t n = points.size();
        #pragma omp for schedule(static)
        for (std::size_t i = 0; i < n; ++i) {
            const Point &p = ptr[i];
            if (p.x >= 0.0) {
                if (p.y >= 0.0)      (*b)[0]++;       // Q1
                else                 (*b)[3]++;       // Q4
            } else {
                if (p.y >= 0.0)      (*b)[1]++;       // Q2
                else                 (*b)[2]++;       // Q3
            }
        }
    }

    // Reduce thread local results into the output array
    bins.fill(0);
    for (const auto &b : localBins) {
        bins[0] += b[0];
        bins[1] += b[1];
        bins[2] += b[2];
        bins[3] += b[3];
    }
}
