06_fft_dft:
```cpp
#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <omp.h>

#if !defined(M_PI)
#define M_PI 3.14159265358979323846
#endif

/* Compute the discrete Fourier transform (DFT) of x.
   The function is fully vectorised and parallelised with OpenMP.
   The algorithm follows the classic definition:
        X[k] = Σ_{n=0}^{N-1} x[n] * exp(-2πi * n * k / N)
   By computing the real and imaginary parts separately we avoid the
   overhead of std::complex arithmetic in the inner loop.
   Parallelism is applied across the output index k with static scheduling.
*/
inline void dft(std::vector<double> const& x, std::vector<std::complex<double>>& output)
{
    const std::size_t N = x.size();
    output.resize(N);

    // Pre‑compute the “twiddle‑factor” step size
    const double two_pi_over_N = 2.0 * M_PI / static_cast<double>(N);

    // Parallelise over output indices
    #pragma omp parallel for schedule(static)
    for (std::ptrdiff_t k = 0; k < static_cast<std::ptrdiff_t>(N); ++k) {
        double sum_real = 0.0;
        double sum_imag = 0.0;

        for (std::ptrdiff_t n = 0; n < static_cast<std::ptrdiff_t>(N); ++n) {
            const double angle = two_pi_over_N * static_cast<double>(n) * static_cast<double>(k);
            const double c = std::cos(angle);
            const double s = std::sin(angle);            // sin(angle) == -(-sin(angle))

            sum_real += x[static_cast<std::size_t>(n)] * c;
            sum_imag -= x[static_cast<std::size_t>(n)] * s; // minus because of e^{-iθ}
        }

        output[static_cast<std::size_t>(k)] = std::complex<double>(sum_real, sum_imag);
    }
}
