#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

struct COOElement {
    std::size_t row, column;
    double value;
};

/* Compute y = alpha*A*x + beta*y where alpha and beta are scalars, x and y are vectors,
   and A is a sparse matrix stored in COO format.
   x and y are length N and A is M x N.
   Example:
   input: alpha=0.5 beta=1.0 A=[{0,1,3}, {1,0,-1}] x=[-4, 2] y=[-1,1]
   output: y=[2, 3]
*/
inline void spmv(double alpha,
                 const std::vector<COOElement> &A,
                 const std::vector<double> &x,
                 double beta,
                 std::vector<double> &y,
                 std::size_t M,
                 std::size_t N)
{
    /* Scale y with beta in parallel */
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < y.size(); ++i)
        y[i] *= beta;

    /* Accumulate contributions from the COO matrix.
       Atomic updates avoid race conditions on y[row]. */
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < A.size(); ++i) {
        const auto &a = A[i];
        if (a.row < M && a.column < N) {
            double v = alpha * a.value * x[a.column];
            #pragma omp atomic
            y[a.row] += v;
        }
    }
}
