#pragma once
#include <vector>
#include <stack>
#include <atomic>
#include <omp.h>

/* Count the number of connected components in the undirected graph defined by the
   adjacency matrix A. A is an NxN row‑major matrix of 0/1s.  
   The implementation uses a parallel depth‑first search with atomic
   visitation flags to preserve deterministic behaviour. */
inline int componentCount(const std::vector<int> &A, size_t N) {
    std::vector<std::atomic<bool>> visited(N);
    for (auto &b : visited) b.store(false, std::memory_order_relaxed);

    std::atomic<int> compCnt(0);

    /* Parallel divide of the outer loop */
#pragma omp parallel for schedule(static)
    for (int start = 0; start < static_cast<int>(N); ++start) {
        if (!visited[start].exchange(true, std::memory_order_acq_rel)) {
            /* New component found */
            compCnt.fetch_add(1, std::memory_order_relaxed);

            std::stack<int> st;
            st.push(start);

            while (!st.empty()) {
                int u = st.top();
                st.pop();

                int base = static_cast<int>(u) * N;
                for (int v = 0; v < static_cast<int>(N); ++v) {
                    if (A[base + v] == 1) {
                        if (!visited[v].exchange(true, std::memory_order_acq_rel)) {
                            st.push(v);
                        }
                    }
                }
            }
        }
    }

    return compCnt.load(std::memory_order_relaxed);
}
