#pragma once
#include <vector>
#include <omp.h>
#include <algorithm>

struct COOElement {
    size_t row, column;
    double value;
};

/* Optimised sparse matrix–matrix multiply
 * Y = A * X
 * A : MxK sparse matrix (COO)
 * X : KxN sparse matrix (COO)
 * Y : dense MxN matrix (row major)
 */
void spmm(std::vector<COOElement> const& A,
          std::vector<COOElement> const& X,
          std::vector<double> &Y,
          size_t M, size_t K, size_t N)
{
    // Initialise the result
    Y.assign(M * N, 0.0);

    /* 1. Build a row‑wise index for X  */
    std::vector<std::vector<COOElement>> xRows(K);
    for (auto const& e : X)
        xRows[e.row].push_back(e);

    /* 2. Parallel accumulation using per‑thread temporaries  */
    const int nthreads = omp_get_max_threads();
    std::vector<std::vector<double>> threadY(nthreads, std::vector<double>(M * N, 0.0));

#pragma omp parallel
    {
        int tid = omp_get_thread_num();
        std::vector<double> &localY = threadY[tid];

#pragma omp for schedule(static)
        for (size_t ai = 0; ai < A.size(); ++ai) {
            const auto &a = A[ai];
            const auto &rowX = xRows[a.column];
            if (rowX.empty()) continue;
            size_t base = a.row * N;
            double av = a.value;
            for (auto const& x : rowX) {
                localY[base + x.column] += av * x.value;
            }
        }
    }

    /* 3. Reduce per‑thread results into Y  */
    for (int t = 0; t < nthreads; ++t) {
        double *dst = Y.data();
        const double *src = threadY[t].data();
        for (size_t i = 0; i < M * N; ++i)
            dst[i] += src[i];
    }
}
