// Optimised 1‑D Jacobi stencil
#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/* Compute one iteration of a 3‑point 1D Jacobi stencil on `input`.
   Each element of `input` will be averaged with its two neighbors and
   stored in the corresponding element of `output`.  Outside of the
   boundaries the index is treated as zero.
*/
inline void jacobi1D(std::vector<double> const& input,
                     std::vector<double> &output)
{
    const size_t n = input.size();
    if (n == 0) return;

    // Handle boundary elements explicitly
    output[0]       = (input[0] + input[1]) / 3.0;
    output[n-1]     = (input[n-2] + input[n-1]) / 3.0;

    // Main bulk – parallelised
    #pragma omp parallel for schedule(static)
    for (size_t i = 1; i + 1 < n; ++i)
    {
        // Local temporaries avoid repeated indexing
        const double left  = input[i-1];
        const double mid   = input[i];
        const double right = input[i+1];
        output[i] = (left + mid + right) / 3.0;
    }
}
