/* Replace the i‑th element of the vector x with the minimum value from indices 0 through i.
   The routine is fully parallel on modern x86‑64 CPUs with OpenMP support. */
inline void partialMinimums(std::vector<float> &x)
{
    const size_t N = x.size();
    if (N == 0) return;

    /* Strike a balance between parallel overhead and granularity.
       If N is tiny we refuse to parallelise. */
    const size_t THRESHOLD = 1 << 12; // 4096 elements
    if (N < THRESHOLD) {
        // fallback to sequential: std::inclusive_scan is fast enough
        std::partial_sum(x.begin(), x.end(), x.begin(),
                         [](const float &a, const float &b)->float {
                             return std::min(a, b);
                         });
        return;
    }

    /* Determine a reasonable chunk size so that each thread
     * handles roughly the same amount of work.  Use a power of two
     * to keep the calculations simple. */
    const size_t chunk = (N + omp_get_max_threads() - 1) / omp_get_max_threads();
    const size_t chunks = (N + chunk - 1) / chunk;

    /* Step 1 – compute the minimum within each chunk    */
    std::vector<float> chunk_mins(chunks);
    #pragma omp parallel for schedule(static)
    for (size_t ci = 0; ci < chunks; ++ci) {
        const size_t begin = ci * chunk;
        const size_t end   = std::min(begin + chunk, N);
        float m = std::numeric_limits<float>::max();
        for (size_t i = begin; i < end; ++i)
            if (x[i] < m) m = x[i];
        chunk_mins[ci] = m;
    }

    /* Step 2 – compute the prefix minima of the chunk minima */
    for (size_t ci = 1; ci < chunks; ++ci)
        chunk_mins[ci] = std::min(chunk_mins[ci], chunk_mins[ci - 1]);

    /* Step 3 – propagate the minima into the original array   */
    #pragma omp parallel for schedule(static)
    for (size_t ci = 0; ci < chunks; ++ci) {
        const size_t begin = ci * chunk;
        const size_t end   = std::min(begin + chunk, N);

        /* Initialise the current minimum with the previous chunk’s global min */
        float m = (ci == 0) ? std::numeric_limits<float>::max() : chunk_mins[ci - 1];

        for (size_t i = begin; i < end; ++i) {
            if (x[i] < m) m = x[i];
            x[i] = m;
        }
    }
}
