```cpp
#pragma once
#include <vector>
#include <cstring>   // for memset

struct COOElement {
    size_t row, column;
    double value;
};

/* 
 * LU factorization of a sparse NxN matrix A (in COO format) into
 * L (unit lower triangular) and U (upper triangular).  The matrices
 * L and U are provided as flat (row‑major) arrays of length N*N
 * and will be overwritten by the result.  The algorithm is
 * identical to the textbook Doolittle method; no pivoting is
 * performed.  The implementation below is carefully written to
 * minimize memory traffic and to use the CPU cache efficiently.
 */
void luFactorize(const std::vector<COOElement> &A,
                 std::vector<double> &L,
                 std::vector<double> &U,
                 size_t N)
{
    /* Allocate a temporary dense matrix for A in row‑major order */
    std::vector<double> fullA(N * N, 0.0);
    for (const auto &el : A) {
        fullA[el.row * N + el.column] = el.value;
    }

    /* Main Doolittle loop */
    for (size_t i = 0; i < N; ++i) {
        /* Compute row i of U */
        double *Ui   = &U[i * N];
        const double *Ai  = &fullA[i * N];

        for (size_t j = i; j < N; ++j) {
            double sum = Ai[j];
            /* Subtract L[i,:k] * U[k,j] for k < i */
            const double *Li = &L[i * N];
            const double *Uk = Ui;                 // temporary pointer
            for (size_t k = 0; k < i; ++k) {
                sum -= Li[k] * Uk[k * N + j];
            }
            Ui[j] = sum;
        }

        /* Compute row i of L (excluding the diagonal 1) */
        for (size_t j = 0; j < i; ++j) {
            double sum = Ai[j];
            const double *Lj = &L[i * N];
            for (size_t k = 0; k < j; ++k) {
                sum -= Lj[k] * U[k * N + j];
            }
            L[i * N + j] = sum / U[j * N + j];
        }

        /* Set unit diagonal */
        L[i * N + i] = 1.0;
    }
}
