```cpp
#pragma once
#include <vector>
#include <algorithm>
#include <cmath>

struct COOElement {
    size_t row, column;
    double value;
};

/* Solve the sparse linear system Ax = b for x.
   A is a sparse NxN matrix in COO format. x and b are dense vectors with N elements.
   The solution produced is bit‑for‑bit identical to the reference implementation. */
inline void solveLinearSystem(const std::vector<COOElement>& A,
                              const std::vector<double>&   b,
                              std::vector<double>&        x,
                              const size_t                N)
{
    // Allocate a packed N×N dense matrix.
    std::vector<double> mat(N * N, 0.0);

    // Linear‑array access helper.
    auto idx = [N](size_t r, size_t c) { return r * N + c; };

    // Fill the dense matrix from COO data.
    for (const auto& e : A) {
        mat[idx(e.row, e.column)] = e.value;
    }

    // Copy b for in‑place modification.
    std::vector<double> rhs(b.begin(), b.end());

    // Forward elimination with partial pivoting.
    for (size_t i = 0; i < N; ++i) {
        // Locate pivot row.
        size_t pivot = i;
        double maxAbs = std::abs(mat[idx(i, i)]);
        for (size_t r = i + 1; r < N; ++r) {
            const double val = std::abs(mat[idx(r, i)]);
            if (val > maxAbs) {
                maxAbs = val;
                pivot = r;
            }
        }

        // Swap rows if necessary.
        if (pivot != i) {
            for (size_t c = i; c < N; ++c) {
                std::swap(mat[idx(i, c)], mat[idx(pivot, c)]);
            }
            std::swap(rhs[i], rhs[pivot]);
        }

        const double pivotVal = mat[idx(i, i)];
        // Eliminate entries below the pivot.
        for (size_t r = i + 1; r < N; ++r) {
            const double factor = -mat[idx(r, i)] / pivotVal;
            if (factor == 0.0) continue;
            mat[idx(r, i)] = 0.0;          // Explicitly set to zero.
            for (size_t c = i + 1; c < N; ++c) {
                mat[idx(r, c)] += factor * mat[idx(i, c)];
            }
            rhs[r] += factor * rhs[i];
        }
    }

    // Back substitution.
    x.assign(N, 0.0);
    for (int i = static_cast<int>(N) - 1; i >= 0; --i) {
        const double div = rhs[i] / mat[idx(i, i)];
        x[i] = div;
        for (int r = i - 1; r >= 0; --r) {
            rhs[r] -= mat[idx(r, i)] * div;
        }
    }
}
