#pragma once
#include <execution>
#include <numeric>
#include <vector>
#include <algorithm>
#include <iterator>

/*
   Compute the inclusive prefix sum of the vector `x` into `output`.
   The function preserves the exact output semantics of the original
   implementation while taking advantage of parallel execution on
   modern x86‑64 CPUs with 8 threads.
*/
inline void prefixSum(const std::vector<int64_t>& x, std::vector<int64_t>& output) {
    // Ensure the output vector has the correct size
    if (output.size() != x.size())
        output.resize(x.size());

    const std::size_t N = x.size();

    if (N == 0) return;

    /* Parallel prefix sum in two phases:

       1. Blockwise local scan (serial within each block but blocks
          processed in parallel).  Each thread computes the inclusive
          scan of its block and records the block total.
       2. Scan the block totals (serial because the number of blocks is
          small).  Each block total is added to all elements of its
          block.

       This algorithm avoids the costly padding required by the
       std::inclusive_scan execution policy and scales well on a
       multi‑core machine.  It also uses the instruction set
       optimisations that the compiler can produce for serial code.
    */

    constexpr std::size_t blockSize = 1 << 12;          // 4096 elements per block
    const std::size_t numBlocks = (N + blockSize - 1) / blockSize;
    std::vector<int64_t> blockTotals(numBlocks);

    // 1. Local scans per block (parallel)
    #pragma omp parallel num_threads(8)
    {
        std::size_t const tid = omp_get_thread_num();
        std::size_t const startBlock = tid;
        std::size_t const stride    = omp_get_num_threads();

        for (std::size_t b = startBlock; b < numBlocks; b += stride) {
            std::size_t startIdx = b * blockSize;
            std::size_t endIdx   = std::min(startIdx + blockSize, N);

            // Simple inclusive scan on this block
            int64_t sum = 0;
            for (std::size_t i = startIdx; i < endIdx; ++i) {
                sum += x[i];
                output[i] = sum;
            }
            blockTotals[b] = sum;
        }
    }

    // 2. Scan the block totals (serial, number of blocks << 8)
    int64_t sum = 0;
    for (std::size_t b = 0; b < numBlocks; ++b) {
        sum += blockTotals[b];
        blockTotals[b] = sum;
    }

    // 3. Add the cumulative block total to each block (parallel)
    #pragma omp parallel for num_threads(8)
    for (std::size_t b = 1; b < numBlocks; ++b) {
        std::size_t startIdx = b * blockSize;
        std::size_t endIdx   = std::min(startIdx + blockSize, N);
        int64_t offset = blockTotals[b - 1];
        for (std::size_t i = startIdx; i < endIdx; ++i)
            output[i] += offset;
    }
}
