int64_t sumOfPrefixSum(const std::vector<int64_t>& x) {
    const std::size_t n = x.size();
    if (n == 0) return 0;

    std::vector<int64_t> prefixSum(n);

    // 1. compute local prefixes
#pragma omp parallel
    {
        const int tid = omp_get_thread_num();
        const int nt  = omp_get_num_threads();

        // divide work into chunks, ensuring all elements are covered
        std::size_t chunk = (n + nt - 1) / nt;
        std::size_t start = tid * chunk;
        std::size_t end   = std::min(start + chunk, n);

        if (start < end) {
            int64_t local_val = 0;
            for (std::size_t i = start; i < end; ++i) {
                local_val += x[i];
                prefixSum[i] = local_val;
            }
        }
    }

    // 2. compute per‑thread totals to add as offsets
    std::vector<int64_t> offsets(omp_get_max_threads() + 1, 0);
    for (int i = 1; i <= static_cast<int>(offsets.size() - 1); ++i)
        offsets[i] = offsets[i - 1];

    // Recompute per-thread totals in parallel
#pragma omp parallel
    {
        const int tid = omp_get_thread_num();
        const int nt  = omp_get_num_threads();
        std::size_t chunk = (n + nt - 1) / nt;
        std::size_t start = tid * chunk;
        std::size_t end   = std::min(start + chunk, n);

        if (start < end) {
            int64_t sum = 0;
            for (std::size_t i = start; i < end; ++i)
                sum += x[i];
#pragma omp atomic
            offsets[tid + 1] += sum;
        }
    }

    // prefix sum of offsets
    for (std::size_t i = 1; i < offsets.size(); ++i)
        offsets[i] += offsets[i - 1];

    // 3. add offsets to each element
#pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < n; ++i) {
        int tid = omp_get_thread_num();
        std::size_t chunk = (n + omp_get_num_threads() - 1) / omp_get_num_threads();
        std::size_t start = tid * chunk;
        std::size_t end   = std::min(start + chunk, n);

        if (i >= start && i < end)
            prefixSum[i] += offsets[tid];
    }

    // 4. final accumulation
    int64_t total = 0;
#pragma omp parallel for reduction(+:total)
    for (std::size_t i = 0; i < n; ++i)
        total += prefixSum[i];

    return total;
}
