/* Compute one iteration of a 5‑point 2D Jacobi stencil on `input`.
   Each element of `input` is averaged with its four neighbours and
   stored in the corresponding element of `output`.  Out‑of‑bounds reads
   are replaced with zero.  The arrays are stored in row‑major order.
*/
inline void jacobi2D(std::vector<double> const& input,
                     std::vector<double> &output,
                     std::size_t N) noexcept
{
    // Pointer to the underlying data for speed.
    const double* in  = input.data();
    double* out         = output.data();

    // Cache the leading dimension for pointer arithmetic.
    const std::size_t stride = N;

    // Parallelise over all elements.  'collapse(2)' distributes the
    // outer two loops among the threads.
    #pragma omp parallel for collapse(2) schedule(static)
    for (std::size_t i = 0; i < N; ++i) {
        const std::size_t base = i * stride;
        const std::size_t ip1  = (i + 1 < N) ? base + stride : base + stride;
        const std::size_t im1  = (i > 0)      ? base - stride : base - stride;

        for (std::size_t j = 0; j < N; ++j) {
            const double* row = in + base;
            double sum = row[j];                           // center

            if (i > 0)      sum += in[im1 + j];            // north
            if (i + 1 < N)  sum += in[ip1 + j];            // south

            if (j > 0)      sum += row[j - 1];             // west
            if (j + 1 < N)  sum += row[j + 1];             // east

            out[base + j] = sum * 0.2;                     // divide by 5
        }
    }
}
