/// Returns the k-th smallest element of the input vector.
/// The input is not modified.  `k` is 1‑based: k = 1 returns the
/// minimum value, k = x.size() returns the maximum.
///
/// This implementation uses `std::nth_element` to achieve linear time on average
/// and avoids the quadratic worst‑case of `std::sort`.
int findKthSmallest(std::vector<int> const& x, int k) {
    // Guard against out-of-range k just in case
    if (k < 1 || k > static_cast<int>(x.size())) {
        throw std::out_of_range("k is out of bounds");
    }

    // Work on a copy to preserve the original vector
    std::vector<int> temp = x;

    // nth_element partially sorts: element at position k-1 is correct
    std::nth_element(temp.begin(), temp.begin() + (k - 1), temp.end());

    return temp[k - 1];
}
