```cpp
#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/* Multiply the matrix A by the vector x. Store the results in the vector y.
 * A is an MxN matrix stored in row‑major, x has N elements, and y has M elements.
 * The routine is parallelized with OpenMP and uses a small cache‑friendly
 * block dimension. It preserves the exact semantics of the original
 * scalar implementation.
 */
inline void gemv(std::vector<double> const& A,
                 std::vector<double> const& x,
                 std::vector<double> &y,
                 size_t M, size_t N)
{
    // Block size tuned experimentally for most cache hierarchies
    constexpr size_t BLOCK = 64;          // rows per block

    // Parallel over blocks of rows
    #pragma omp parallel for schedule(static, BLOCK)
    for (size_t bi = 0; bi < M; bi += BLOCK) {
        size_t i_end = std::min(bi + BLOCK, M);
        const double* a_ptr = &A[bi * N];
        double*       y_ptr = &y[bi];

        for (size_t i = bi; i < i_end; ++i, a_ptr += N, y_ptr += 1) {
            double sum = 0.0;
            const double* a_row = a_ptr;
            const double* x_ptr  = x.data();

            // Unroll by 4 for inner loop
            size_t j = 0;
            size_t limit = N & ~size_t(3);
            for (; j < limit; j += 4) {
                sum += a_row[j]     * x_ptr[j];
                sum += a_row[j + 1] * x_ptr[j + 1];
                sum += a_row[j + 2] * x_ptr[j + 2];
                sum += a_row[j + 3] * x_ptr[j + 3];
            }
            for (; j < N; ++j) {
                sum += a_row[j] * x_ptr[j];
            }
            *y_ptr = sum;
        }
    }
}
