```cpp
#pragma once
#include <vector>
#include <algorithm>
#include <cmath>

struct Point
{
    double x, y;
};

/* Fast Euclidean distance --------------------------------------------- */
inline double dist(const Point& a, const Point& b)
{
    double dx = a.x - b.x;
    double dy = a.y - b.y;
    return std::sqrt(dx * dx + dy * dy);
}

/*  2‑D convex hull (Monotone chain) ------------------------------------ */
double convexHullPerimeter(const std::vector<Point>& points)
{
    // No polygon can be formed with fewer than 3 points
    if (points.size() < 3)
        return 0.0;

    /* Sort points by (x, y) ------------------------------------------- */
    std::vector<Point> sorted(points);
    std::sort(sorted.begin(), sorted.end(),
              [](const Point& a, const Point& b)
              {
                  return a.x < b.x || (a.x == b.x && a.y < b.y);
              });

    /* Cross product of AB × AC ---------------------------------------- */
    auto cross = [](const Point& a, const Point& b, const Point& c) -> double
    {
        return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
    };

    /* Build lower and upper hulls ------------------------------------- */
    const size_t n = sorted.size();
    std::vector<Point> hull(2 * n);
    size_t k = 0;

    for (size_t i = 0; i < n; ++i)
    {
        while (k >= 2 && cross(hull[k - 2], hull[k - 1], sorted[i]) <= 0.0)
            --k;
        hull[k++] = sorted[i];
    }

    // Build upper hull
    for (size_t i = n - 1, t = k + 1; i > 0; --i)
    {
        while (k >= t && cross(hull[k - 2], hull[k - 1], sorted[i - 1]) <= 0.0)
            --k;
        hull[k++] = sorted[i - 1];
    }
    hull.resize(k - 1);            // last point is same as first

    /* Compute perimeter ----------------------------------------------- */
    double perimeter = 0.0;
    for (size_t i = 0; i < hull.size() - 1; ++i)
        perimeter += dist(hull[i], hull[i + 1]);

    perimeter += dist(hull.back(), hull.front());
    return perimeter;
}
