/* Simulate one generation of Game of Life on `input`. Store the results in `output`.
   Input and output are NxN grids stored in row‑major order.  Each cell is 0 or 1.  */
inline void gameOfLife(const std::vector<int>& input, std::vector<int>& output, std::size_t N)
{
    // Use raw pointers for best performance
    const int*  in  = input.data();
    int*       out = output.data();

    // Parallelise the outer loop; the workload is embarrassingly parallel
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i)
    {
        const std::size_t offset = i * N;
        for (std::size_t j = 0; j < N; ++j)
        {
            int sum = 0;
            // Access neighbouring cells; explicit boundary checks minimise
            // branches inside the inner loop (the compiler will optimise the
            // comparisons heavily at -O2)
            if (i > 0) sum += in[(i-1)*N + j];
            if (i+1 < N) sum += in[(i+1)*N + j];
            if (j > 0) sum += in[offset + j-1];
            if (j+1 < N) sum += in[offset + j+1];
            if (i>0 && j>0) sum += in[(i-1)*N + j-1];
            if (i>0 && j+1<N) sum += in[(i-1)*N + j+1];
            if (i+1<N && j>0) sum += in[(i+1)*N + j-1];
            if (i+1<N && j+1<N) sum += in[(i+1)*N + j+1];

            const int cur = in[offset + j];
            // Apply the classic Game‑of‑Life rules
            if (cur == 1)
            {
                out[offset + j] = (sum == 2 || sum == 3) ? 1 : 0;
            }
            else
            {
                out[offset + j] = (sum == 3) ? 1 : 0;
            }
        }
    }
}
