    for (std::size_t i = 0; i < N; ++i) {
        const std::size_t iN = i * N;
        for (std::size_t j = 0; j < N; ++j) {
            int sum = 0;

            /* Manually unroll the kernel for minimal branch overhead. */
            // k = -1
            if (i > 0) {
                if (j > 0)   sum += -imageIn[(i-1)*N + j-1];
                sum +=           8*imageIn[(i-1)*N + j];
                if (j+1 < N) sum += -imageIn[(i-1)*N + j+1];
            }

            // k =  0
            if (j > 0)   sum += -imageIn[iN + j-1];
            if (j+1 < N) sum += -imageIn[iN + j+1];

            // k =  1
            if (i+1 < N) {
                if (j > 0)   sum += -imageIn[(i+1)*N + j-1];
                sum +=           8*imageIn[(i+1)*N + j];
                if (j+1 < N) sum += -imageIn[(i+1)*N + j+1];
            }

