#pragma once
#include <vector>
#include <cmath>
#include <limits>
#include <algorithm>
#include <omp.h>

struct Point {
    double x, y;
};

inline double getDist(const Point& a, const Point& b) noexcept {
    double dx = b.x - a.x;
    double dy = b.y - a.y;
    return std::sqrt(dx * dx + dy * dy);
}

/* Return the distance between the closest two points in the vector points. */
double closestPair(const std::vector<Point>& points) {
    const std::size_t n = points.size();
    if (n < 2) {
        return 0.0;
    }

    // Sort points by x coordinate once to enable the O(n log n) divide & conquer
    std::vector<Point> pts = points;
    std::sort(pts.begin(), pts.end(), [](const Point& a, const Point& b) {
        return a.x < b.x;
    });

    // Helper function: recursive divide & conquer
    std::function<double(std::size_t, std::size_t)> solve = [&](std::size_t l, std::size_t r) -> double {
        if (r - l <= 3) {
            double d = std::numeric_limits<double>::max();
            for (std::size_t i = l; i < r; ++i) {
                for (std::size_t j = i + 1; j < r; ++j) {
                    d = std::min(d, getDist(pts[i], pts[j]));
                }
            }
            return d;
        }

        std::size_t m = (l + r) / 2;
        double xm = pts[m].x;

        double d = std::min(solve(l, m), solve(m, r));

        // Build strip
        std::vector<Point> strip;
        strip.reserve(r - l);
        for (std::size_t i = l; i < r; ++i) {
            if (std::fabs(pts[i].x - xm) < d) {
                strip.push_back(pts[i]);
            }
        }

        // Sort strip by y
        std::sort(strip.begin(), strip.end(), [](const Point& a, const Point& b) {
            return a.y < b.y;
        });

        // Check against next at most 7 points
        const std::size_t sz = strip.size();
        for (std::size_t i = 0; i < sz; ++i) {
            for (std::size_t j = i + 1; j < sz && (strip[j].y - strip[i].y) < d; ++j) {
                d = std::min(d, getDist(strip[i], strip[j]));
            }
        }
        return d;
    };

    return solve(0, n);
}
