#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

// Parallelised LU factorisation – exact semantic equivalent to the original.
//   A is stored row‑major as a contiguous std::vector<double> of size N*N.
inline void luFactorize(std::vector<double> &A, std::size_t N) {
    // Common optimisation: cache the row stride once.
    const std::size_t stride = N;

    // The outer L/U elimination loop – must be executed sequentially.
    for (std::size_t k = 0; k < N; ++k) {
        const double pivot = A[k * stride + k];      // A[k][k]
        // Parallelise the inner work over rows i = k+1 … N-1.
        // The elimination for a given i only depends on the current pivot row,
        // which is stable for the duration of this k‑iteration.
        #pragma omp parallel for schedule(static, 64)
        for (std::size_t i = k + 1; i < N; ++i) {
            double *Ai   = &A[i * stride];          // pointer to row i
            const double *Ak = &A[k * stride];      // pointer to row k
            const double factor = Ai[k] / pivot;     // A[i][k] / A[k][k]
            Ai[k] = factor;                         // store L element

            // Update the remaining elements in the row.
            // Loop unrolling of 4 gives a small speed bump on modern CPUs.
            std::size_t j = k + 1;
            for (; j + 3 < N; j += 4) {
                Ai[j]   -= factor * Ak[j];
                Ai[j+1] -= factor * Ak[j+1];
                Ai[j+2] -= factor * Ak[j+2];
                Ai[j+3] -= factor * Ak[j+3];
            }
            for (; j < N; ++j) {
                Ai[j] -= factor * Ak[j];
            }
        }
    }
}
