#pragma once
#include <vector>
#include <algorithm>
#include <cstddef>

struct Point
{
    double x, y;
};

/*
    Computes the vertices of the convex hull of a planar point set.
    The returned hull is in counter‑clockwise order, starting with the
    lexicographically smallest point (by x, then y).  The implementation
    follows the monotone chain algorithm with small inlined optimisations
    suitable for GCC 12+ on x86‑64, as requested.
*/
inline void convexHull(const std::vector<Point> &points, std::vector<Point> &hull)
{
    const std::size_t n = points.size();
    if (n < 3) {             // degenerate case
        hull = points;
        return;
    }

    // --- 1. Sort points lexicographically ------------------------------------
    std::vector<Point> pts = points;
    std::sort(pts.begin(), pts.end(),
              [](const Point &a, const Point &b) {
                  return a.x < b.x || (a.x == b.x && a.y < b.y);
              });

    // --- 2. Monotone chain ----------------------------------------------------
    // pre‑allocate result buffer (max size 2n-1)
    std::vector<Point> hullbuf;
    hullbuf.reserve(2 * n);
    std::size_t k = 0;      // current size of hullbuf

    // inline cross product: (b-a)×(c-a)
    auto cross = [](const Point &a, const Point &b, const Point &c) -> double {
        return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
    };

    // lower hull
    for (std::size_t i = 0; i < n; ++i) {
        const Point &pt = pts[i];
        while (k >= 2 &&
               cross(hullbuf[k - 2], hullbuf[k - 1], pt) <= 0.0) {
            --k;                      // pop
        }
        hullbuf[k++] = pt;
    }

    // upper hull
    std::size_t t = k + 1;           // index where upper part starts
    for (std::size_t i = n; i > 0; --i) {
        const Point &pt = pts[i - 1];
        while (k >= t &&
               cross(hullbuf[k - 2], hullbuf[k - 1], pt) <= 0.0) {
            --k;
        }
        hullbuf[k++] = pt;
    }

    // one vertex is duplicated (first point == last point), remove it
    hullbuf.resize(k - 1);
    hull.swap(hullbuf);              // fast move semantics
}
