#include <omp.h>

/* Solve the linear system Ax = b (NxN) using Gaussian elimination with partial
   pivoting. The function preserves the original behaviour and return value.
   Inputs:
      A – row‑major matrix (size N*N)
      b – right‑hand side vector (size N)
   Output:
      x – solution vector (size N)
   Notes:
      • The input vectors are not modified.
      • The algorithm stops with an empty solution if a pivot element is 0.
*/
inline void solveLinearSystem(const std::vector<double>& A,
                              const std::vector<double>& b,
                              std::vector<double>& x,
                              const std::size_t N)
{
    // Work on local copies (row‑major order)
    std::vector<double> Acopy = A;
    std::vector<double> bcopy = b;

    for (std::size_t i = 0; i + 1 < N; ++i)
    {
        const double pivot = Acopy[i * N + i];
        if (pivot == 0.0) return;          // singular matrix – abort

#pragma omp parallel for schedule(static)
        for (std::size_t j = i + 1; j < N; ++j)
        {
            const double factor = Acopy[j * N + i] / pivot;
            double* Aj = &Acopy[j * N];
            const double* Ai = &Acopy[i * N];
            for (std::size_t k = i; k < N; ++k)
                Aj[k] -= factor * Ai[k];
            bcopy[j] -= factor * bcopy[i];
        }
    }

    // Back‑substitution (sequential – data is small, no need to parallelise)
    for (int i = static_cast<int>(N) - 1; i >= 0; --i)
    {
        double sum = 0.0;
        for (std::size_t j = i + 1; j < N; ++j)
            sum += Acopy[i * N + j] * x[j];
        x[i] = (bcopy[i] - sum) / Acopy[i * N + i];
    }
}
