#pragma once
#include <vector>
#include <atomic>
#include <cstddef>
#include <omp.h>

/* Return true if `val` is only in one of vectors x or y.
   Return false if it is in both or neither.
   The function keeps the exact semantics of the original
   implementation – it stops as soon as it knows the result
   and guarantees no data races. */
inline bool xorContains(const std::vector<int>& x, const std::vector<int>& y, int val)
{
    // Atomic flags that will be set to true when val is found.
    std::atomic<bool> foundX{false}, foundY{false};

    // Search vector x in parallel.
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < x.size(); ++i) {
        if (!foundX.load(std::memory_order_relaxed) && x[i] == val)
            foundX.store(true, std::memory_order_relaxed);
    }

    // If already found in both, result is false (early exit).
    if (foundX.load(std::memory_order_relaxed))
        return false;   // cannot be true if also found in y

    // Search vector y in parallel.
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < y.size(); ++i) {
        if (!foundY.load(std::memory_order_relaxed) && y[i] == val)
            foundY.store(true, std::memory_order_relaxed);
    }

    // Result: true if found in exactly one vector.
    return foundX.load(std::memory_order_relaxed) ^ foundY.load(std::memory_order_relaxed);
}
