        xi[n] = x[n].imag();
    }

    /* 2. Pre‑compute twiddle factors for each stage */
    const size_t logN = static_cast<size_t>(std::log2(N));
    std::vector<double> wre(logN), wim(logN);
    for (size_t s = 1; s <= logN; ++s) {
        double theta = -M_PI / (1 << (s-1));
        wre[s-1] = std::cos(theta);
        wim[s-1] = std::sin(theta);
    }

    /* 3. Iterative radix‑2 butterfly (decimation‑in‑time) */
    size_t len = 1;
    for (size_t s = 0; s < logN; ++s, len <<= 1) {
        const double wr0 = wre[s];
        const double wi0 = wim[s];
        for (size_t i0 = 0; i0 < N; i0 += (len << 1)) {
            double wr = 1.0, wi = 0.0;          // twiddle factor for first butterfly
            for (size_t j = 0; j < len; ++j) {
                size_t a = i0 + j;
                size_t b = a + len;
                double tr = xr[b] * wr - xi[b] * wi;
                double ti = xr[b] * wi + xi[b] * wr;
                xr[b] = xr[a] - tr;
                xi[b] = xi[a] - ti;
                xr[a] += tr;
                xi[a] += ti;
                // Next twiddle factor: rotate by w0
                double tmp = wr * wr0 - wi * wi0;
                wi = wr * wi0 + wi * wr0;
                wr = tmp;
            }
        }
    }

    /* 4. Bit‑reversal permutation (parallel) */
    #pragma omp parallel for schedule(static)
    for (size_t a = 0; a < N; ++a) {
        size_t b = a;
        // Reverse lower 32 bits (since N is power of 2, N <= 2^32)
        b = ((b&0x55555555)<<1) | ((b&0xaaaaaaaa)>>1);
        b = ((b&0x33333333)<<2) | ((b&0xcccccccc)>>2);
        b = ((b&0x0f0f0f0f)<<4) | ((b&0xf0f0f0f0)>>4);
        b = ((b&0x00ff00ff)<<8) | ((b&0xff00ff00)>>8);
        b = ((b&0x0000ffff)<<16) | ((b&0xffff0000)>>16);
        b >>= (32 - logN);
        if (b > a) {
            std::swap(xr[a], xr[b]);
            std::swap(xi[a], xi[b]);
        }
    }

    /* 5. Write final results into output vectors */
    #pragma omp parallel for schedule(static)
    for (size_t n = 0; n < N; ++n) {
        r[n] = xr[n];
        i[n] = xi[n];
    }
}
