/* Optimised matrix multiply.
 * A: MxK, B: KxN, C: MxN (row‑major). 
 * C is assumed pre‑initialised to zero (or any desired bias).
 */
inline void gemm(std::vector<double> const& A,
                 std::vector<double> const& B,
                 std::vector<double> &C,
                 size_t M, size_t K, size_t N)
{
    // Tile sizes tuned for L1/L2 cache (~ 8‑KB and 256‑KB respectively).
    constexpr size_t BM = 64;   // rows of A / C
    constexpr size_t BK = 64;   // columns of A / rows of B
    constexpr size_t BN = 64;   // columns of B / C

    const double *restrict a = A.data();
    const double *restrict b = B.data();
          double *restrict c = C.data();

    #pragma omp parallel for schedule(static)
    for (size_t ii = 0; ii < M; ii += BM) {
        size_t i_max = (ii + BM > M) ? M : ii + BM;
        for (size_t jj = 0; jj < N; jj += BN) {
            size_t j_max = (jj + BN > N) ? N : jj + BN;
            for (size_t kk = 0; kk < K; kk += BK) {
                size_t k_max = (kk + BK > K) ? K : kk + BK;

                // Per‑block loop nest
                for (size_t i = ii; i < i_max; ++i) {
                    const double *ai = a + i*K;
                    double *ci = c + i*N + jj;
                    for (size_t k = kk; k < k_max; ++k) {
                        double aik = ai[k];
                        const double *bk = b + k*N + jj;
                        // Inner loop over j unrolled by 4
                        size_t j = 0;
                        for (; j + 3 < j_max - jj; j += 4) {
                            ci[j]     += aik * bk[j];
                            ci[j + 1] += aik * bk[j + 1];
                            ci[j + 2] += aik * bk[j + 2];
                            ci[j + 3] += aik * bk[j + 3];
                        }
                        for (; j < j_max - jj; ++j) {
                            ci[j] += aik * bk[j];
                        }
                    }
                }
            }
        }
    }
}
