#include <omp.h>

#if !defined(M_PI)
#define M_PI 3.14159265358979323846
#endif

/* ------------------------------------------------------------------
 *  Optimised iterative radix‑2 FFT / IFFT (in‑place)
 *  ----------------------------------------------------------
 *  * Uses pre‑computed twiddle factors
 *  * Bits‑reverse is performed in a classic in‑place manner
 *  * The outer butterfly loops are parallelised with OpenMP
 *  * Exact semantics of the reference implementation are preserved
 *  ------------------------------------------------------------------*/

static void fft_helper(std::vector<std::complex<double>>& x)
{
    const std::size_t N = x.size();
    if (N <= 1) return;               // nothing to do

    // -----------------------------------------------------------------
    // 1) Pre‑compute twiddle factors for every stage
    //    W_N^k = exp(-2πi * k / N)
    // -----------------------------------------------------------------
    const std::size_t stages = static_cast<std::size_t>(std::log2(N));
    std::vector<std::complex<double>> twiddles(N / 2);
    double two_pi = -2.0 * M_PI;
    for (std::size_t i = 0; i < N / 2; ++i)
        twiddles[i] = std::polar(1.0, two_pi * static_cast<double>(i) / static_cast<double>(N));

    // -----------------------------------------------------------------
    // 2) Butterfly (decimation‑in‑time) pass
    // -----------------------------------------------------------------
    std::size_t m = 1;                // size of the sub‑FFT
    for (std::size_t s = 0; s < stages; ++s)
    {
        std::size_t half = m;
        std::size_t step = m << 1;   // 2*m

        // Parallelise over the groups of 'm' butterflies
        #pragma omp parallel for schedule(static)
        for (std::size_t k = 0; k < N; k += step)
        {
            std::size_t j = 0;
            for (std::size_t i = k; i < k + half; ++i)
            {
                std::complex<double> t = x[i + half] * twiddles[j];
                x[i + half] = x[i] - t;
                x[i] += t;
                ++j;
            }
        }
        m = step;                     // double the size for next stage
    }

    // -----------------------------------------------------------------
    // 3) Bit‑reversal permutation
    // -----------------------------------------------------------------
    std::size_t j = 0;
    for (std::size_t i = 0; i < N; ++i)
    {
        if (j > i)
            std::swap(x[i], x[j]);

        std::size_t bit = N >> 1;
        while (j & bit)
        {
            j ^= bit;
            bit >>= 1;
        }
        j ^= bit;
    }
}

inline void ifft(std::vector<std::complex<double>>& x)
{
    // Conjugate, forward FFT, conjugate again, then scale
    std::transform(x.begin(), x.end(), x.begin(),
                   [](const std::complex<double>& c){ return std::conj(c); });
    fft_helper(x);
    std::transform(x.begin(), x.end(), x.begin(),
                   [](const std::complex<double>& c){ return std::conj(c); });
    const double invN = 1.0 / static_cast<double>(x.size());
    #pragma omp parallel for
    for (std::size_t i = 0; i < x.size(); ++i)
        x[i] *= invN;
}
