/* Return the index of the value in the vector x that is closest to the math constant PI.
   Use M_PI for the value of PI.
   Example:
   input: [9.18, 3.05, 7.24, 11.3, -166.49, 2.1]
   output: 1
*/
size_t findClosestToPi(std::vector<double> const& x) {
    if (x.empty())
        return static_cast<size_t>(-1);   // undefined for empty, but be safe

    // declare a custom reduction for a pair of (difference, index)
    #pragma omp declare reduction(                                 \
        min_pair : std::pair<double,size_t> :                         \
            omp_out = ( omp_in.first < omp_out.first ? omp_in : omp_out ) \
    ) initializer( omp_priv = { std::numeric_limits<double>::infinity(), static_cast<size_t>(-1) } );

    std::pair<double,size_t> best = {std::abs(x[0] - M_PI), 0};

    #pragma omp parallel for reduction(min_pair:best) schedule(static)
    for (size_t i = 1; i < x.size(); ++i) {
        double d = std::abs(x[i] - M_PI);
        best = std::make_pair(d, i);
    }

    return best.second;
}
