inline void ranks(std::vector<float> const& x, std::vector<size_t> &ranks_) {
    // create a vector of (value, original_index) pairs
    std::vector<std::pair<float,size_t>> pairs(x.size());
    for (size_t i = 0; i < x.size(); ++i) {
        pairs[i] = {x[i], i};
