    // sort pairs by value; stable sort is not needed but used for consistency with original
    std::sort(pairs.begin(), pairs.end(),
              [](auto const& a, auto const& b){ return a.first < b.first; });

    // write ranks
    for (size_t i = 0; i < pairs.size(); ++i) {
        ranks_[pairs[i].second] = i;
    }
}
