#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <cstdint>
#include <algorithm>
#include <omp.h>

#ifndef M_PI
#define M_PI 3.14159265358979323846L
#endif

namespace detail {
    // Pre‑computed twiddle factor cache
    struct TwiddleCache {
        TwiddleCache(std::size_t n) : n_(n), cache_(n / 2) {
            double angle = -M_PI / n_;
            for (std::size_t k = 0; k < n_ / 2; ++k) {
                cache_[k] = std::exp(std::complex<double>(0.0, angle * static_cast<double>(k)));
            }
        }
        const std::complex<double>* data() const { return cache_.data(); }
    private:
        std::size_t n_;
        std::vector<std::complex<double>> cache_;
    };

    // In‑place radix‑2 Cooley–Tukey FFT
    inline void radix2_fft(std::vector<std::complex<double>>& a, const TwiddleCache& twiddles) noexcept {
        const std::size_t n = a.size();
        const std::size_t log_n = static_cast<std::size_t>(std::log2(n));

        // --- Bit‑reversal permutation ------------------------------------
        std::vector<std::size_t> rev(n);
        for (std::size_t i = 0; i < n; ++i) {
            std::size_t r = i;
            r = ((r & 0x55555555U) << 1) | ((r & 0xAAAAAAAAU) >> 1);
            r = ((r & 0x33333333U) << 2) | ((r & 0xCCCCCCCCU) >> 2);
            r = ((r & 0x0F0F0F0FU) << 4) | ((r & 0xF0F0F0F0U) >> 4);
            r = ((r & 0x00FF00FFU) << 8) | ((r & 0xFF00FF00U) >> 8);
            r = (r << 16) | (r >> 16);
            rev[i] = r >> (32 - log_n);
        }
        #pragma omp parallel for schedule(static)
        for (std::size_t i = 0; i < n; ++i) {
            if (rev[i] > i) std::swap(a[i], a[rev[i]]);
        }

        // --- Main FFT loop ------------------------------------------------
        std::size_t step = 1;
        for (std::size_t m = 1; m <= log_n; ++m) {
            const std::size_t half = step;
            const std::size_t twice = step * 2;
            const std::complex<double>* tw = twiddles.data();
            #pragma omp parallel for schedule(static)
            for (std::size_t i = 0; i < n; i += twice) {
                for (std::size_t j = 0; j < half; ++j) {
                    std::size_t idx = i + j;
                    std::size_t idx2 = idx + half;
                    std::complex<double> u = a[idx];
                    std::complex<double> t = tw[j * n / twice] * a[idx2];
                    a[idx] = u + t;
                    a[idx2] = u - t;
                }
            }
            step = twice;
        }
    }
} // namespace detail

/// FFT wrapper matching the harness signature
inline void fft(std::vector<std::complex<double>> const& x,
                std::vector<std::complex<double>>& output) {
    const std::size_t n = x.size();
    output = x;                               // copy input
    static thread_local std::size_t cached_n = 0;
    static thread_local std::unique_ptr<detail::TwiddleCache> twiddles;

    if (cached_n != n) {
        twiddles = std::make_unique<detail::TwiddleCache>(n);
        cached_n = n;
    }
    detail::radix2_fft(output, *twiddles);
}
