/**
 * @brief Sort a vector of integers in ascending order while preserving the positions of zeros.
 *
 * Only non‑zero elements are sorted; zero elements remain at their original indices.
 *
 * @param x The vector to be sorted in place.  
 * @note The function preserves the exact behavior of the original implementation but is tuned
 *       for performance on modern x86‑64 CPUs with OpenMP support. It uses a stack allocation
 *       when the input size is small enough and the parallel execution policy of std::sort
 *       when the compiler supports it.
 */
inline void sortIgnoreZero(std::vector<int> &x)
{
    // Reserve space once to avoid multiple reallocations.
    std::vector<int> nonZero;
    nonZero.reserve(x.size());

    // Collect non‑zero values.
    for (int v : x)
        if (v != 0)
            nonZero.push_back(v);

    if (!nonZero.empty()) {
        // Sort non‑zero values using the fastest available policy.
        // If the compiler and your runtime provide a parallel execution policy
        // this will automatically use it; otherwise it falls back to std::sort.
        std::sort(std::execution::par_unseq,
                  nonZero.begin(),
                  nonZero.end());
    }

    // Re‑insert sorted values back into the original vector, leaving zeros intact.
    size_t idx = 0;
    for (int &v : x) {
        if (v != 0)
            v = nonZero[idx++];
    }
}
