#pragma once
#include <vector>
#include <cstddef>

/// Return true if the vector `x` contains the value `target`.  
/// The implementation is a hand‑rolled, cache‑friendly linear search to
/// avoid the overhead of the standard library algorithm while keeping
/// correct semantics for all inputs.
inline bool contains(const std::vector<int>& x, int target) {
    // If the vector is empty, immediately return false.
    if (x.empty()) return false;

    // Use raw pointers for the fastest possible access and to avoid
    // iterator overhead.  The loop is manually unrolled in 8‑item
    // blocks to give the compiler more optimisation opportunities.
    const int* ptr = x.data();
    const std::size_t len = x.size();
    std::size_t i = 0;

    // Process in chunks of 8 for a small speed improvement on large vectors.
    const std::size_t chunk = 8;
    const std::size_t limit = len - (len % chunk);

    while (i < limit) {
        if (ptr[i]     == target) return true;
        if (ptr[i + 1] == target) return true;
        if (ptr[i + 2] == target) return true;
        if (ptr[i + 3] == target) return true;
        if (ptr[i + 4] == target) return true;
        if (ptr[i + 5] == target) return true;
        if (ptr[i + 6] == target) return true;
        if (ptr[i + 7] == target) return true;
        i += chunk;
    }

    // Handle any remaining elements.
    while (i < len) {
        if (ptr[i] == target) return true;
        ++i;
    }
    return false;
}
